# --- Session ID Validation ---
# Only allow hex characters of exact expected length to prevent
# path traversal and injection attacks.
sub validate_session_id {
    my ($session_id) = @_;
    return 0 unless defined $session_id;
    return 0 unless length($session_id) == $SESSION_ID_LENGTH;
    return 0 unless $session_id =~ /\A[0-9a-f]+\z/;
    return 1;
}

# --- Safe Session File Path Construction ---
# Prevents path traversal by validating the ID and confirming
# the resolved path stays within SESSION_DIR.
sub session_file_path {
    my ($session_id) = @_;
    unless (validate_session_id($session_id)) {
        return undef;
    }
    my $path = File::Spec->catfile($SESSION_DIR, "sess_${session_id}.json");

    # Resolve to absolute path and verify it's within SESSION_DIR
