    unless ($abs_path =~ /\A\Q$abs_dir\E\//) {
        warn "Path traversal attempt detected for session ID: $session_id";
        return undef;
    }
    return $abs_path;
}

# --- Generate Cryptographically Secure Session ID ---
sub generate_session_id {
    my $random_bytes = '';
    if (open(my $fh, '<', '/dev/urandom')) {
        read($fh, $random_bytes, 32);
        close($fh);
    } else {
        # Fallback: use combination of sources
        $random_bytes = join('', map { chr(int(rand(256))) } 1..32);
    }
    return sha256_hex($random_bytes . time() . $$);
}

# --- Serialize Session Data Using JSON (Safe, Data-Only Format) ---
