# --- Sanitize Session Data ---
# Only allow plain data types (strings, numbers) in session.
# Reject references to objects, code refs, globs, etc.
sub sanitize_session_data {
    my ($data) = @_;
    return {} unless ref($data) eq 'HASH';

    my $clean = {};
    for my $key (keys %$data) {
        # Only allow simple alphanumeric keys (with underscores)
        next unless $key =~ /\A[a-zA-Z_][a-zA-Z0-9_]{0,63}\z/;

        my $value = $data->{$key};

        if (!defined $value) {
            $clean->{$key} = undef;
        } elsif (ref($value) eq '') {
            # Plain scalar - truncate to reasonable length
            $clean->{$key} = substr($value, 0, 4096);
        } elsif (ref($value) eq 'ARRAY') {
            # Allow simple arrays of scalars
            $clean->{$key} = sanitize_array($value);
        } elsif (ref($value) eq 'HASH') {
            # Allow nested hashes (one level deep)
            $clean->{$key} = sanitize_session_data($value);
        }
        # Silently drop code refs, blessed objects, globs, etc.
    }
    return $clean;
}

sub sanitize_array {
    my ($arr) = @_;
    return [] unless ref($arr) eq 'ARRAY';
    my @clean;
    for my $item (@$arr) {
        if (!defined $item) {
            push @clean, undef;
        } elsif (ref($item) eq '') {
            push @clean, substr($item, 0, 4096);
        }
        # Drop non-scalar array elements
    }
    return \@clean;
}

# --- Destroy Session ---
sub destroy_session {
    my ($session_id) = @_;

    unless (validate_session_id($session_id)) {
        return 0;
    }

    my $file = session_file_path($session_id);
    return 0 unless defined $file;

    if (-f $file) {
        unlink($file) or warn "Cannot delete session file: $!";
    }
    return 1;
}

# --- Session Middleware / Handler ---
sub get_or_create_session {
    my ($cgi) = @_;
    $cgi ||= CGI->new();

    my %cookies = CGI::Cookie->fetch();
    my $session_id;
    my $session_data;
    my $is_new = 0;

    # Try to load existing session from cookie
    if (exists $cookies{'session_id'}) {
        $session_id = $cookies{'session_id'}->value();

        if (validate_session_id($session_id)) {
            $session_data = load_session($session_id);
        }
    }

    # Create new session if needed
    unless ($session_data) {
        $session_id = generate_session_id();
        $session_data = {
            _created       => time(),
            _last_accessed => time(),
        };
        $is_new = 1;
    }

    return ($session_id, $session_data, $is_new);
}

# --- Create Session Cookie ---
sub create_session_cookie {
    my ($session_id) = @_;

    return CGI::Cookie->new(
        -name     => 'session_id',
        -value    => $session_id,
        -path     => '/',
        -httponly  => 1,
        -secure   => 1,
        -samesite => 'Strict',
        -expires  => '+1h',
    );
}

# --- Cleanup Expired Sessions ---
sub cleanup_expired_sessions {
    opendir(my $dh, $SESSION_DIR) or do {
        warn "Cannot open session directory: $!";
        return;
    };

    my $now = time();
    my $cleaned = 0;

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /\Asess_([0-9a-f]{$SESSION_ID_LENGTH})\.json\z/;
        my $sid = $1;
        my $file = session_file_path($sid);
        next unless defined $file && -f $file;

        my @stat = stat($file);
        if (@stat && ($now - $stat[9]) > $SESSION_TIMEOUT) {
            unlink($file);
            $cleaned++;
        }
    }
    closedir($dh);
    return $cleaned;
}

